function scanPStr = fScanParamV01(scanNDir,scanNS)%% find out scan parameter% % scanPStr = fScanParamV01(scanNDir,scanNS)% % scanPStr: scan parameter string%% scanNDir: scan# dir% scanNS: scan# string, '003'%%% Function scan parameter string% % Kei Nakamura% 2015/9/14 ver.1: created by Hann%% main bodyParaPath = [scanNDir filesep 'ScanInfoScan' scanNS '.ini'];StrP = fileread(ParaPath);QuoteS = strfind(StrP,'"');ParaS = strfind(StrP,'r = "') + 4;scanPStr = StrP(ParaS+1:max(QuoteS)-1);
